 19→ALFPHexGridManager* ULFPMapEditorComponent::GetGridManager() const
 20→{
 21→	if (!CachedGridManager)
 22→	{
 23→		TArray<AActor*> Managers;
 24→		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPHexGridManager::StaticClass(), Managers);
 25→		if (Managers.Num() > 0)
 26→		{
 27→			CachedGridManager = Cast<ALFPHexGridManager>(Managers[0]);
 28→		}
 29→	}
 30→	return CachedGridManager;
 31→}
