120→bool ULFPMapEditorComponent::SaveMap(const FString& FileName)
121→{
122→	ALFPHexGridManager* GM = GetGridManager();
123→	if (!GM) return false;
124→
125→	FString FullPath = GetMapSaveDirectory() / FileName + TEXT(".csv");
126→	return GM->SaveMapToCSV(FullPath);
127→}
