129→bool ULFPMapEditorComponent::LoadMap(const FString& FileName)
130→{
131→	ALFPHexGridManager* GM = GetGridManager();
132→	if (!GM) return false;
133→
134→	FString FullPath = GetMapSaveDirectory() / FileName + TEXT(".csv");
135→	return GM->LoadMapFromCSV(FullPath);
136→}
