152→void ULFPMapEditorComponent::NewMap(int32 Width, int32 Height)
153→{
154→	ALFPHexGridManager* GM = GetGridManager();
155→	if (!GM) return;
156→
157→	GM->GenerateGrid(Width, Height);
158→	UE_LOG(LogTemp, Log, TEXT("新建地图: %dx%d"), Width, Height);
159→}
