  24→ALFPTacticsPlayerController::ALFPTacticsPlayerController()
  25→{
  26→    TargetUnit = nullptr;
  27→    SelectedUnit = nullptr;
  28→    SelectedTile = nullptr;
  29→    bIsSelecting = false;
  30→    bIsAttacking = false;
  31→    CameraRotationPitchAngle = 60.0f;
  32→    CameraRotationYawAngle = 0.0f;
  33→    bDebugEnabled = false;
  34→    CameraOffset = FVector::ZeroVector;
  35→    bIsDragging = false;
  36→    CurrentControlState = EPlayControlState::MoveState;
  37→    LastControlState = CurrentControlState;
