 107→void ALFPTacticsPlayerController::SetupInputComponent()
 108→{
 109→    Super::SetupInputComponent();
 110→
 111→    // 绑定Enhanced Input组件
 112→    if (UEnhancedInputComponent* EnhancedInputComponent = Cast<UEnhancedInputComponent>(InputComponent))
