 260→// 选择开始
 261→void ALFPTacticsPlayerController::OnSelectStarted(const FInputActionValue& Value)
 262→{
 263→    if (bWaitingForMove) return;
 264→
 265→    bIsSelecting = true;
 266→
 267→    // 获取鼠标位置
 268→    float MouseX, MouseY;
 269→    if (GetMousePosition(MouseX, MouseY))
 270→    {
 271→        SelectionStart = FVector2D(MouseX, MouseY);
 272→    }
 273→}
 274→
 275→// 选择完成
 276→void ALFPTacticsPlayerController::OnSelectCompleted(const FInputActionValue& Value)
 277→{
 278→    if (bWaitingForMove) return;
 279→    if (!bIsSelecting) return;
 280→    bIsSelecting = false;
 281→
 282→    // 获取鼠标位置
 283→    float MouseX, MouseY;
 284→    GetMousePosition(MouseX, MouseY);
 285→    FVector2D SelectionEnd = FVector2D(MouseX, MouseY);
 286→
 287→    // 简单的点击检测（非拖拽）
 288→    if (FVector2D::Distance(SelectionStart, SelectionEnd) < 10.0f)
 289→    {
 290→        FHitResult HitResult;
 291→        GetHitResultAtScreenPosition(SelectionEnd, ECC_Visibility, false, HitResult);
 292→
 293→        if (HitResult.bBlockingHit)
 294→        {
 295→            // 尝试选中单位
 296→            ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(HitResult.GetActor());
 297→            if (Unit)
 298→            {
 299→                SelectUnit(Unit);
 300→                return;
 301→            }
 302→
 303→            // 尝试选中格子
 304→            ALFPHexTile* Tile = Cast<ALFPHexTile>(HitResult.GetActor());
 305→            if (Tile)
 306→            {
 307→                SelectTile(Tile);
 308→                return;
 309→            }
 310→        }
 311→    }
 312→}
