109→ALFPHexTile* ALFPHexGridManager::SpawnTileAt(int32 Q, int32 R, ELFPTerrainType TerrainType,
110→	FName DecorationID, ELFPSpawnFaction SpawnFaction, int32 SpawnIndex, FGameplayTag EventTag)
111→{
112→	FIntPoint Key(Q, R);
113→	// 如果已存在则跳过
114→	if (GridMap.Contains(Key)) return GridMap[Key];
115→
116→	FLFPHexCoordinates HexCoord(Q, R);
117→	FVector WorldLocation = HexCoord.ToWorldLocation(HexSize, VerticalScale) + GetActorLocation();
118→
119→	FActorSpawnParameters SpawnParams;
120→	SpawnParams.Owner = this;
121→	ALFPHexTile* NewTile = GetWorld()->SpawnActor<ALFPHexTile>(
122→		HexTileClass,
123→		WorldLocation,
124→		FRotator::ZeroRotator,
125→		SpawnParams
126→	);
127→
128→	if (!NewTile) return nullptr;
129→
130→	NewTile->SetCoordinates(HexCoord);
131→	NewTile->AttachToActor(this, FAttachmentTransformRules::KeepWorldTransform);
132→
133→	// 应用地形：优先从注册表查找，否则用默认地形
134→	if (ULFPTerrainDataAsset* TerrainDA = GetTerrainDataForType(TerrainType))
135→	{
136→		NewTile->SetTerrainData(TerrainDA);
137→	}
138→	else if (DefaultTerrainData)
139→	{
140→		NewTile->SetTerrainData(DefaultTerrainData);
141→	}
142→
143→	// 应用装饰
144→	if (!DecorationID.IsNone())
145→	{
146→		NewTile->SetDecorationByID(DecorationID, GetDecorationSprite(DecorationID));
147→	}
148→
149→	// 应用出生点和事件数据
150→	NewTile->SpawnFaction = SpawnFaction;
151→	NewTile->SpawnIndex = SpawnIndex;
152→	NewTile->EventTag = EventTag;
153→
154→	// 初始化边缘和覆盖层组件
155→	NewTile->InitializeEdgeComponents(EdgeHighlightSprite, RangeOverlaySprite, HexSize, VerticalScale);
156→
157→	// 初始化基础地形材质（始终应用）
158→	if (TerrainBaseMaterial)
159→	{
160→		NewTile->InitializeBaseMaterial(TerrainBaseMaterial,
161→			TerrainTextureScale, HexMaskScale, HexMaskYScale);
162→	}
163→
164→	// 初始化过渡组件（仅在启用时）
165→	if (bEnableTerrainTransition && TerrainTransitionMaterial && TransitionHexSprite)
166→	{
167→		NewTile->InitializeTransitionComponents(TransitionHexSprite,
168→			TerrainTransitionMaterial,
169→			TerrainTextureScale, HexMaskScale, HexMaskYScale);
170→	}
171→
172→	GridMap.Add(Key, NewTile);
173→	return NewTile;
174→}
