228→	if (!FFileHelper::LoadFileToString(CSVContent, *CSVFilePath))
229→	{
230→		UE_LOG(LogTemp, Error, TEXT("LoadMapFromCSV: 无法加载文件 %s"), *CSVFilePath);
231→		return false;
232→	}
233→
234→	// 使用临时 DataTable 解析 CSV
235→	UDataTable* TempTable = NewObject<UDataTable>(GetTransientPackage());
236→	TempTable->RowStruct = FLFPMapTileRow::StaticStruct();
237→
238→	TArray<FString> Problems = TempTable->CreateTableFromCSVString(CSVContent);
239→	if (Problems.Num() > 0)
240→	{
241→		for (const FString& Problem : Problems)
242→		{
243→			UE_LOG(LogTemp, Warning, TEXT("CSV 解析问题: %s"), *Problem);
244→		}
245→	}
246→
247→	LoadMapFromDataTable(TempTable);
248→	return true;
249→}
