383→TArray<ALFPHexTile*> ALFPHexGridManager::GetTilesInRange(ALFPHexTile* Center, int32 MaxRange, int32 MinRange)
384→{
385→	TArray<ALFPHexTile*> ReachableTiles;
386→	if (!Center || MaxRange <= 0) return ReachableTiles;
387→
388→	// Dijkstra 数据结构（支持变代价地形）
389→	TMap<ALFPHexTile*, int32> MoveCosts;
390→	TArray<ALFPHexTile*> OpenList;
391→
392→	OpenList.Add(Center);
393→	MoveCosts.Add(Center, 0);
394→
395→	while (OpenList.Num() > 0)
396→	{
397→		// 找到代价最小的节点
398→		int32 MinCostIndex = 0;
399→		int32 MinCost = MoveCosts[OpenList[0]];
400→		for (int32 i = 1; i < OpenList.Num(); i++)
401→		{
402→			int32 Cost = MoveCosts[OpenList[i]];
403→			if (Cost < MinCost)
404→			{
405→				MinCost = Cost;
406→				MinCostIndex = i;
407→			}
408→		}
409→
410→		ALFPHexTile* CurrentTile = OpenList[MinCostIndex];
411→		OpenList.RemoveAt(MinCostIndex);
412→		int32 CurrentCost = MoveCosts[CurrentTile];
413→
414→		// 获取所有邻居
415→		for (ALFPHexTile* Neighbor : GetNeighbors(CurrentTile->GetCoordinates()))
416→		{
417→			if (!Neighbor || !Neighbor->IsWalkable() || Neighbor->IsOccupied()) continue;
418→
419→			// 计算移动代价（使用地形代价）
420→			const int32 NewCost = CurrentCost + Neighbor->GetMovementCost();
421→
422→			// 如果未访问或找到更短路径
423→			if (!MoveCosts.Contains(Neighbor) || NewCost < MoveCosts[Neighbor])
424→			{
425→				MoveCosts.Add(Neighbor, NewCost);
426→
427→				// 在移动范围内才加入开放列表
428→				if (NewCost <= MaxRange)
429→				{
430→					OpenList.Add(Neighbor);
431→				}
432→			}
433→		}
434→	}
435→
436→	// 收集所有可达格子（排除起点，应用最小范围过滤）
437→	for (auto& Pair : MoveCosts)
438→	{
439→		if (Pair.Key != Center && Pair.Value >= MinRange && Pair.Value <= MaxRange)
440→		{
441→			ReachableTiles.Add(Pair.Key);
442→		}
443→	}
444→
445→	return ReachableTiles;
446→}
