458→TArray<ALFPHexTile*> ALFPHexGridManager::FindPath(ALFPHexTile* Start, ALFPHexTile* End)
459→{
460→	TArray<ALFPHexTile*> Path;
461→
462→	// 验证输入有效性
463→	if (!Start || !End || !End->IsWalkable())
464→	{
465→		UE_LOG(LogTemp, Warning, TEXT("FindPath: Invalid start or end tile"));
466→		return Path;
467→	}
468→
469→	// 如果起点和终点相同
470→	if (Start == End) {
471→		Path.Add(Start);
472→		UE_LOG(LogTemp, Log, TEXT("FindPath: Start and end are the same tile"));
473→		return Path;
474→	}
475→
476→	// 寻路数据结构
477→	TMap<ALFPHexTile*, ALFPHexTile*> ParentMap;
478→	TMap<ALFPHexTile*, float> GScoreMap;  // 实际移动代价
479→	TSet<ALFPHexTile*> OpenSet;
480→	TSet<ALFPHexTile*> ClosedSet;
481→
482→	// 初始化起点
483→	OpenSet.Add(Start);
484→	GScoreMap.Add(Start, 0.0f);
485→	ParentMap.Add(Start, nullptr);
486→
487→	bool bPathFound = false;
488→
489→	while (!OpenSet.IsEmpty())
490→	{
491→		// 获取开放集中F值最小的节点
492→		ALFPHexTile* Current = nullptr;
493→		float LowestF = TNumericLimits<float>::Max();
494→
495→		for (ALFPHexTile* Tile : OpenSet)
496→		{
497→			const float G = GScoreMap[Tile];
498→			const float H = FLFPHexCoordinates::Distance(Tile->GetCoordinates(), End->GetCoordinates());
499→			const float F = G + H;
